int climbStairsHelper(int n, vector<int>& memo)
{
    if (n <= 2) return n;
    if (memo[n] != -1) return memo[n]; // check cache first

    memo[n] = climbStairsHelper(n - 1, memo) + climbStairsHelper(n - 2, memo); // store before returning
