#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int coinChangeHelper(int amount, vector<int>& coins)
{
    if (amount == 0) return 0;
    if (amount < 0) return INT_MAX;

    int best = INT_MAX;
    for (int coin : coins)
    {
        int sub = coinChangeHelper(amount - coin, coins);
        if (sub != INT_MAX) best = min(best, sub + 1);
    }
    return best;
}

int coinChange(vector<int>& coins, int amount)
{
    int result = coinChangeHelper(amount, coins);
    return result == INT_MAX ? -1 : result;
}

