#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int coinChangeHelper(int amount, vector<int>& coins, vector<int>& memo)
{
    if (amount == 0) return 0;
    if (amount < 0) return INT_MAX;
    if (memo[amount] != -2) return memo[amount];

    int best = INT_MAX;
    for (int coin : coins)
    {
        int sub = coinChangeHelper(amount - coin, coins, memo);
        if (sub != INT_MAX) best = min(best, sub + 1);
    }

    memo[amount] = best;
    return best;
}

int coinChange(vector<int>& coins, int amount)
{
    vector<int> memo(amount + 1, -2); // -2 = not yet computed (distinct from INT_MAX, a valid 'impossible' result)
    int result = coinChangeHelper(amount, coins, memo);
    return result == INT_MAX ? -1 : result;
}

int main()
{
    vector<int> coins = {1, 2, 5};
    cout << coinChange(coins, 11);

    return 0;
}

